CREATE VIEW `dim_tag_center_activity_info_view` (`actity_id` COMMENT "主活动id", `actity_name` COMMENT "活动名称", `start_time` COMMENT "开始时间", `end_time` COMMENT "结束时间", `status` COMMENT "状态 1 开启，2 关闭", `create_time` COMMENT "创建时间", `lang_id` COMMENT "语言id", `actity_type` COMMENT "活动类型 1：定向充值，2：push,3:edm充值活动,4:推书活动活动(指定书籍),5:其他活动,6:消费活动 7:组合活动，8:推书活动活动(书单)，9:充值档位活动，10:新福利包档位活动, 11:svip档位活动，12:抽奖活动，13:限免卡活动，14:限免卡档位活动", `second_type` COMMENT "二级类型 1：阅读打卡 ,2指定书籍（后展示书籍配置控件）,3章节更新", `combin_page_id` COMMENT "组合页面id", `st_id` COMMENT "策略id", `st_name` COMMENT "策略名称", `st_lang_id` COMMENT "策略语言id", `st_group_ids` COMMENT "分组id", `st_start_time` COMMENT "开始时间", `st_end_time` COMMENT "结束时间", `st_status` COMMENT "策略状态", `st_create_time` COMMENT "策略创建时间", `st_update_time` COMMENT "策略更新时间", `st_template_id` COMMENT "模板id", `st_main_id` COMMENT "主活动id")
COMMENT "tag后台活动配置信息表" AS SELECT `ods`.`a`.`id` AS `actity_id`, `ods`.`a`.`name` AS `actity_name`, `ods`.`a`.`starttime` AS `start_time`, `ods`.`a`.`endtime` AS `end_time`, `ods`.`a`.`status`, `ods`.`a`.`createtime` AS `create_time`, `ods`.`a`.`langid` AS `lang_id`, `ods`.`a`.`actitytype` AS `actity_type`, `ods`.`a`.`secondtype` AS `second_type`, `ods`.`a`.`combinpageid` AS `combin_page_id`, `ods`.`b`.`id` AS `st_id`, `ods`.`b`.`name` AS `st_name`, `ods`.`b`.`langid` AS `st_lang_id`, `ods`.`b`.`groupids` AS `st_group_ids`, `ods`.`b`.`starttime` AS `st_start_time`, `ods`.`b`.`endtime` AS `st_end_time`, `ods`.`b`.`status` AS `st_status`, `ods`.`b`.`createtime` AS `st_create_time`, `ods`.`b`.`updatetime` AS `st_update_time`, `ods`.`b`.`templateid` AS `st_template_id`, `ods`.`b`.`mainid` AS `st_main_id`
FROM `ods`.`ods_tidb_readernovel_tidb_tag_center_activity_main` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_readernovel_tidb_tag_center_activity` AS `b` ON `ods`.`a`.`id` = `ods`.`b`.`mainid`;
